#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>

int main() {
    pid_t pid;

    printf("Before fork - Parent Process\n");

    pid = fork();  // System call to create new process

    if (pid < 0) {
        // Error occurred
        printf("Fork failed!\n");
        return 1;
    }
    else if (pid == 0) {
        // Child process
        printf("Child Process: My PID = %d, Parent PID = %d\n", 
               getpid(), getppid());
    }
    else {
        // Parent process
        printf("Parent Process: My PID = %d, Child PID = %d\n", 
               getpid(), pid);
    }

    return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <string.h>
#include <sys/types.h>

int main() {
    int pipefd[2];  // File descriptors for pipe
    pid_t pid;
    char write_msg[] = "Message from parent to child";
    char read_msg[100];

    // Create pipe - system call
    if (pipe(pipefd) == -1) {
        perror("pipe failed");
        return 1;
    }

    pid = fork();  // Create child process

    if (pid > 0) {
        // Parent process
        close(pipefd[0]);  // Close read end
        write(pipefd[1], write_msg, strlen(write_msg) + 1);
        close(pipefd[1]);  // Close write end
    }
    else {
        // Child process
        close(pipefd[1]);  // Close write end
        read(pipefd[0], read_msg, 100);
        printf("Child received: %s\n", read_msg);
        close(pipefd[0]);  // Close read end
    }

    return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/time.h>
#include <sys/resource.h>

int main() {
    pid_t pid, ppid;
    uid_t uid;
    gid_t gid;
    struct rusage usage;

    // Get process ID - information maintenance system call
    pid = getpid();
    printf("Process ID (PID): %d\n", pid);

    // Get parent process ID
    ppid = getppid();
    printf("Parent Process ID (PPID): %d\n", ppid);

    // Get user ID
    uid = getuid();
    printf("User ID (UID): %d\n", uid);

    // Get group ID
    gid = getgid();
    printf("Group ID (GID): %d\n", gid);

    // Get resource usage
    getrusage(RUSAGE_SELF, &usage);
    printf("User CPU time: %ld.%06ld sec\n", 
           usage.ru_utime.tv_sec, usage.ru_utime.tv_usec);
    printf("System CPU time: %ld.%06ld sec\n", 
           usage.ru_stime.tv_sec, usage.ru_stime.tv_usec);

    return 0;
}
